import React, { Component } from 'react';
import { withRouter, Link } from 'react-router-dom';
import axios from 'axios';
import { createUrl } from '../../../functions/ImageUrl';
import s from './Categories.module.scss';
import $ from 'jquery';

class Categories extends Component {

    constructor(props) {
        super(props);
        this.state = {
            categories: [],
            test: [1,1,1]
        };
    }

    componentDidMount() {
        axios.get(`${process.env.REACT_APP_GLOBAL_API_URL}/categories/all`, { params: { cache_id: "Categories_All" } }).then(res => {
            if (res.data.status === 1) {
                this.setState({ categories: res.data.categories });
            }
        });
    }

    render() {
        return (
            <main className={s.main}>
                <div className={s.categories}>
                    <div className={s.ctgrid}>
                        {this.state.categories.map((obj, key) => <div className={s['ctgrid-item']}>
                            <Link to={`/kategorie/${obj.seo_url}`}></Link>
                            <div className={s['ctgrid-item__inner']}>
                                <div className={s['ctgrid-item__image']}>
                                    <img src={createUrl(obj.cover_pic, "_medium")}/>
                                    <div className={s['ctgrid-item__caption']}>
                                        <span>{obj.name}</span>
                                        <div className={s['ctgrid-item__btn']}>
                                            <p>Wybierz</p>
                                        </div>
                                    </div>
                                </div>    
                            </div>     
                        </div>)}
                    </div>
                </div>
                <video width="100%" height="100%" loop="" muted="" autoplay="" playsinline="" poster="/on/demandware.static/-/Library-Sites-PatagoniaShared/default/dw34e9dd43/images/heros/Hero_16-9_Trail-Hub-backUpHero-doscher_b_0045-notCCd-FPO.jpg">
<source src="https://www.patagonia.com/media/marketing/videos/2019_site_ambient_videos_trail_running_v01.mp4" type="video/mp4"/>
</video>
            </main>
        )
    }
}

export default withRouter(Categories);
